questionvariables.text:
/* 1. Randomize the side length s (between 4 and 10) */
s: 4 + rand(7);

/* 2. Calculate a realistic apothem (a = s / (2*tan(22.5))) */
/* For a regular octagon, the apothem is approx 1.2071 * side */
a_exact: float(s / (2 * tan(%pi/8)));
a: decimalplaces(a_exact,2);

/* 3. Calculate Area of ONE triangle: 1/2 * base * height */
area_tri: (1/2) * s * a;

/* 4. Total Area of Octagon: 8 * area of one triangle */
/* Using the formula A = 4 * s * a */
ta_1: float(4 * s * a);
ta: decimalplaces(ta_1,2);
